import{_ as a,o as e,c as d,ag as r}from"./chunks/framework.C6K0jwmI.js";const b=JSON.parse('{"title":"オーナーダッシュボード","description":"","frontmatter":{"title":"オーナーダッシュボード"},"headers":[],"relativePath":"tenant/15-owner.md","filePath":"tenant/15-owner.md"}'),o={name:"tenant/15-owner.md"};function l(i,t,n,h,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="_15-オーナーダッシュボード" tabindex="-1">15. オーナーダッシュボード <a class="header-anchor" href="#_15-オーナーダッシュボード" aria-label="Permalink to &quot;15. オーナーダッシュボード&quot;">​</a></h1><p>オーナーダッシュボードは、複数店舗の管理、本部機能、ユーザー管理、契約・決済設定を行う画面です。オーナーロールのユーザーが利用します。</p><h2 id="主な機能" tabindex="-1">主な機能 <a class="header-anchor" href="#主な機能" aria-label="Permalink to &quot;主な機能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>内容</th></tr></thead><tbody><tr><td>店舗管理</td><td>店舗の追加、編集、状態確認</td></tr><tr><td>ユーザー管理</td><td>マネージャー、スタッフ、端末専用アカウントの管理</td></tr><tr><td>クロス店舗レポート</td><td>複数店舗の売上や実績を横断比較</td></tr><tr><td>ABC分析</td><td>売上貢献度をもとに商品の傾向を確認</td></tr><tr><td>本部メニュー</td><td>多店舗向けのメニュー一括管理</td></tr><tr><td>決済設定</td><td>Stripeや決済関連情報の確認・設定</td></tr></tbody></table><h2 id="店舗を追加する" tabindex="-1">店舗を追加する <a class="header-anchor" href="#店舗を追加する" aria-label="Permalink to &quot;店舗を追加する&quot;">​</a></h2><ol><li>店舗管理を開きます。</li><li>店舗名、住所、営業時間、税率などを入力します。</li><li>保存後、必要なマネージャーを所属させます。</li><li>店舗側でメニュー、テーブル、決済、プリンタを設定します。</li></ol><h2 id="ユーザー管理" tabindex="-1">ユーザー管理 <a class="header-anchor" href="#ユーザー管理" aria-label="Permalink to &quot;ユーザー管理&quot;">​</a></h2><p>オーナーは全店舗のユーザーを管理できます。退職者や異動者がいる場合は、速やかにアカウントを無効化または所属店舗を変更してください。</p><h2 id="複数店舗レポート" tabindex="-1">複数店舗レポート <a class="header-anchor" href="#複数店舗レポート" aria-label="Permalink to &quot;複数店舗レポート&quot;">​</a></h2><p>店舗別売上、商品傾向、スタッフ実績を横断して確認できます。期間と対象店舗をそろえて比較してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>店舗が表示されない</td><td>店舗の登録状態と契約内容を確認してください。</td></tr><tr><td>ユーザーがログインできない</td><td>所属店舗、ロール、パスワードを確認してください。</td></tr><tr><td>本部メニューが使えない</td><td>契約プランまたはオプションを確認してください。</td></tr><tr><td>決済設定が進まない</td><td>入力内容を確認し、必要に応じてPOSLAサポートへお問い合わせください。</td></tr></tbody></table>',12)])])}const p=a(o,[["render",l]]);export{b as __pageData,p as default};
